1492→                                            onChange={(event) => setDoodleColor(event.target.value)}
1493→                                            className={styles.colorInput}
1494→                                            title="Custom doodle color"
1495→                                        />
1496→                                    </label>
1497→                                </div>
1498→                                <div className={styles.toolbarRow}>
1499→                                    <input
1500→                                        type="range"
1501→                                        min={1}
1502→                                        max={10}
1503→                                        step={0.2}
1504→                                        value={doodleSize}
1505→                                        onChange={(event) => setDoodleSize(Number(event.target.value))}
1506→                                        className={styles.sizeRange}
1507→                                        aria-label="Doodle size"
1508→                                    />
1509→                                    <button type="button" className={styles.secondaryButton} onClick={undoLastDoodle} disabled={doodles.length === 0}>
1510→                                        Undo Doodle
1511→                                    </button>
1512→                                    <button type="button" className={styles.secondaryButton} onClick={clearDoodles} disabled={doodles.length === 0 && !isDrawing}>
1513→                                        Clear Doodles
1514→                                    </button>
1515→                                    <span className={styles.toolHint}>Draw directly on wall</span>
1516→                                </div>
1517→                            </div>
1518→                        )}
1519→
1520→                        {activeTool === "select" && selectedObject && (
1521→                            <div className={styles.selectionPanel}>
1522→                                {selectedSnippet && (
1523→                                    <div className={styles.styleCarousel}>
1524→                                        {Object.entries(FONT_BRUSHES).map(([styleKey, styleValue]) => {
1525→                                            const isActive = selectedSnippet.fontStyle === styleKey;
1526→                                            return (
1527→                                                <button
1528→                                                    key={styleKey}
1529→                                                    type="button"
1530→                                                    className={`${styles.fontChip} ${isActive ? styles.fontChipActive : ""}`}
1531→                                                    onClick={() => updateSnippet(selectedSnippet.id, {fontStyle: styleKey})}
1532→                                                >
1533→                                                    <span className={styles.fontChipLabel}>{styleValue.label}</span>
1534→                                                    <span
1535→                                                        className={styles.fontChipPreview}
1536→                                                        style={{
1537→                                                            fontFamily: styleValue.fontFamily,
1538→                                                            fontStyle: styleValue.fontStyle
1539→                                                        }}
1540→                                                    >
1541→                                                        {styleValue.preview}
1542→                                                    </span>
1543→                                                </button>
1544→                                            );
1545→                                        })}
1546→                                    </div>
1547→                                )}
1548→
1549→                                <div className={styles.toolbarRow}>
1550→                                    <button type="button" className={styles.secondaryButton} onClick={() => resizeSelectedObject("down")}>Resize -</button>
1551→                                    <button type="button" className={styles.secondaryButton} onClick={() => resizeSelectedObject("up")}>Resize +</button>
1552→                                    <button type="button" className={styles.secondaryButton} onClick={() => rotateSelectedObject(-8)}>Rotate -</button>
1553→                                    <button type="button" className={styles.secondaryButton} onClick={() => rotateSelectedObject(8)}>Rotate +</button>
1554→                                    <button type="button" className={styles.secondaryButton} onClick={flipSelectedObject}>Flip</button>
1555→                                    <button type="button" className={styles.secondaryButton} onClick={bringToFront}>Front</button>
1556→                                    <button type="button" className={styles.secondaryButton} onClick={sendToBack}>Back</button>
1557→                                    <button type="button" className={styles.secondaryButton} onClick={removeSelectedObject}>Remove</button>
1558→                                </div>
1559→                            </div>
1560→                        )}
1561→
1562→                        <div className={styles.toolbarRow}>
1563→                            <div className={styles.aspectToggle}>
1564→                                <button
1565→                                    type="button"
1566→                                    className={`${styles.secondaryButton} ${canvasMeta.aspectRatio === "1:1" ? styles.toolButtonActive : ""}`}
1567→                                    onClick={() => setCanvasMeta((prev) => ({...prev, aspectRatio: "1:1"}))}
1568→                                >
1569→                                    1:1
1570→                                </button>
1571→                                <button
1572→                                    type="button"
1573→                                    className={`${styles.secondaryButton} ${canvasMeta.aspectRatio === "4:5" ? styles.toolButtonActive : ""}`}
1574→                                    onClick={() => setCanvasMeta((prev) => ({...prev, aspectRatio: "4:5"}))}
1575→                                >
1576→                                    4:5
1577→                                </button>
1578→                            </div>
1579→                            <button
1580→                                type="button"
1581→                                className={`${styles.secondaryButton} ${canvasMeta.gridEnabled ? styles.toolButtonActive : ""}`}
1582→                                onClick={() => setCanvasMeta((prev) => ({...prev, gridEnabled: !prev.gridEnabled}))}
1583→                            >
1584→                                Grid
1585→                            </button>
1586→                            <button
1587→                                type="button"
1588→                                className={`${styles.secondaryButton} ${canvasMeta.snapEnabled ? styles.toolButtonActive : ""}`}
1589→                                onClick={() => setCanvasMeta((prev) => ({...prev, snapEnabled: !prev.snapEnabled}))}
1590→                            >
1591→                                Snap
1592→                            </button>
1593→                            <button
1594→                                type="button"
1595→                                className={`${styles.secondaryButton} ${canvasMeta.theme === "dark" ? styles.toolButtonActive : ""}`}
1596→                                onClick={() => setCanvasMeta((prev) => ({...prev, theme: prev.theme === "dark" ? "light" : "dark"}))}
1597→                            >
1598→                                {canvasMeta.theme === "dark" ? "Dark" : "Light"}
1599→                            </button>
1600→                            <button type="button" className={styles.secondaryButton} onClick={() => zoomByStep("out")}>Zoom -</button>
1601→                            <button type="button" className={styles.secondaryButton} onClick={() => zoomByStep("in")}>Zoom +</button>
1602→                            <button type="button" className={styles.secondaryButton} onClick={resetViewport}>Reset View</button>
1603→                        </div>
1604→                    </div>
1605→                )}
1606→            </div>
1607→        </div>
1608→    );
1609→};
1610→
1611→export default CanvasEditor;
